```java
class Student implements Comparable<Student> {
    String name;
    double gpa;

    Student(String name, double gpa) { this.name = name; this.gpa = gpa; }

    @Override public int compareTo(Student other) {
        return Double.compare(this.gpa, other.gpa);  // ascending GPA
    }

    @Override public String toString() {
        return String.format("%s (%.2f)", name, gpa);
    }
}
```

```java
public List<String> removeInactive(List<Student> students, double threshold) {
    List<String> removed = new ArrayList<>();

    Iterator<Student> it = students.iterator();
    while (it.hasNext()) {
        Student s = it.next();
        if (s.gpa < threshold) {
            removed.add(s.name + " (" + s.gpa + ")");  // log before removing
            it.remove();
        }
    }
    return removed;
}
```

Cannot use `removeIf` here cleanly because we need to build the log list simultaneously. Iterator gives us access to the element before removal.

```java
public void awardBonus(List<Student> students, double bonus) {
    ListIterator<Student> lit = students.listIterator();
    while (lit.hasNext()) {
        Student s = lit.next();
        lit.set(new Student(s.name, Math.min(4.0, s.gpa + bonus)));
    }
}
```

`lit.set()` replaces the current element in-place. Capped at 4.0 (max GPA).

```java
public void classStats(List<Student> students) {
    if (students.isEmpty()) return;

    Student best = Collections.max(students);   // uses Comparable
    Student worst = Collections.min(students);

    double total = 0;
    for (Student s : students) total += s.gpa;
    double avg = total / students.size();

    System.out.printf("Best: %s | Worst: %s | Avg: %.2f%n",
        best, worst, avg);
}

public List<Student> topStudents(List<Student> students, int n) {
    List<Student> sorted = new ArrayList<>(students);  // copy!
    Collections.sort(sorted, Collections.reverseOrder()); // descending
    return sorted.subList(0, Math.min(n, sorted.size()));
}

public List<Student> getReadOnlyRoster(List<Student> students) {
    return Collections.unmodifiableList(students);
}
```

worked_example.final_code:
import java.util.*;

class Student implements Comparable<Student> {
    String name;
    double gpa;
    Student(String name, double gpa) { this.name = name; this.gpa = gpa; }
    @Override public int compareTo(Student o) { return Double.compare(this.gpa, o.gpa); }
    @Override public String toString() { return String.format("%s(%.2f)", name, gpa); }
}

public class StudentManager {
    static List<String> removeInactive(List<Student> students, double threshold) {
        List<String> log = new ArrayList<>();
        Iterator<Student> it = students.iterator();
        while (it.hasNext()) {
            Student s = it.next();
            if (s.gpa < threshold) { log.add(s.toString()); it.remove(); }
        }
        return log;
    }

    static void awardBonus(List<Student> students, double bonus) {
        ListIterator<Student> lit = students.listIterator();
        while (lit.hasNext()) {
            Student s = lit.next();
            lit.set(new Student(s.name, Math.min(4.0, s.gpa + bonus)));
        }
    }

    static void classStats(List<Student> students) {
        double total = 0;
        for (Student s : students) total += s.gpa;
        System.out.printf("Best: %s | Worst: %s | Avg: %.2f%n",
            Collections.max(students), Collections.min(students), total / students.size());
    }

    static List<Student> topN(List<Student> students, int n) {
        List<Student> copy = new ArrayList<>(students);
        copy.sort(Collections.reverseOrder());
        return copy.subList(0, Math.min(n, copy.size()));
    }

    public static void main(String[] args) {
        List<Student> roster = new ArrayList<>(Arrays.asList(
            new Student("Aisha", 3.8),
            new Student("Raj", 2.1),
            new Student("Priya", 3.5),
            new Student("Vikram", 1.9),
            new Student("Anita", 3.9)
        ));

        System.out.println("Initial: " + roster);

        List<String> removed = removeInactive(roster, 2.5);
        System.out.println("Removed (below 2.5): " + removed);
        System.out.println("After removal: " + roster);

        awardBonus(roster, 0.1);
        System.out.println("After bonus: " + roster);

        classStats(roster);
        System.out.println("Top 2: " + topN(roster, 2));

        List<Student> readOnly = Collections.unmodifiableList(roster);
        System.out.println("Read-only size: " + readOnly.size());
        try {
            readOnly.add(new Student("Extra", 4.0));
        } catch (UnsupportedOperationException e) {
            System.out.println("Cannot modify read-only list!");
        }
    }
}
